CREATE DATABASE IF NOT EXISTS parasja_app CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE parasja_app;

CREATE TABLE IF NOT EXISTS parasjot (
    id INT AUTO_INCREMENT PRIMARY KEY,
    volgorde INT NOT NULL,
    naam_hebreeuws VARCHAR(100) NOT NULL,
    naam_nl VARCHAR(100) NOT NULL,
    naam_transliteratie VARCHAR(100) NOT NULL,
    boek ENUM('Bereshit','Shemot','Vayikra','Bamidbar','Devarim') NOT NULL,
    verzen_van VARCHAR(50),
    verzen_tot VARCHAR(50),
    samenvatting TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS parasja_schema (
    id INT AUTO_INCREMENT PRIMARY KEY,
    parasja_id INT NOT NULL,
    shabbat_datum DATE NOT NULL,
    joods_jaar INT NOT NULL,
    gecombineerd_met INT DEFAULT NULL,
    FOREIGN KEY (parasja_id) REFERENCES parasjot(id),
    UNIQUE KEY unique_datum (shabbat_datum)
);

CREATE TABLE IF NOT EXISTS notities (
    id INT AUTO_INCREMENT PRIMARY KEY,
    parasja_id INT NOT NULL,
    parasja_schema_id INT DEFAULT NULL,
    titel VARCHAR(255),
    tekst TEXT NOT NULL,
    aangemaakt_op TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    bijgewerkt_op TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (parasja_id) REFERENCES parasjot(id)
);

CREATE TABLE IF NOT EXISTS foto_notities (
    id INT AUTO_INCREMENT PRIMARY KEY,
    parasja_id INT NOT NULL,
    parasja_schema_id INT DEFAULT NULL,
    bestandsnaam VARCHAR(255) NOT NULL,
    origineel_naam VARCHAR(255),
    ocr_tekst TEXT,
    ocr_bewerkt TEXT,
    notitie VARCHAR(255),
    aangemaakt_op TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (parasja_id) REFERENCES parasjot(id)
);

